const query = $input.first().json.query || {};
const verifyToken = $env.RIFAH_VERIFY_TOKEN || 'rifah_verify_token_2024';

if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === verifyToken) {
  return [{ json: { challenge: query['hub.challenge'], valid: true } }];
}
return [{ json: { challenge: 'ERROR', valid: false } }];

// Parse Meta Cloud API Webhook Payload
const body = $input.first().json.body || $input.first().json;

const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;

// Ignore status updates (delivery receipts etc)
if (value?.statuses && !value?.messages) {
  return [{ json: { skip: true, reason: 'status_update' } }];
}

const messages = value?.messages;
if (!messages || messages.length === 0) {
  return [{ json: { skip: true, reason: 'no_message' } }];
}

const msg = messages[0];
const contact = value?.contacts?.[0];

const extracted = {
  skip: false,
  from: msg.from,
  from_name: contact?.profile?.name || 'Unknown',
  message_id: msg.id,
  timestamp: msg.timestamp,
  type: msg.type,
  text: msg.text?.body || '',
  phone_number_id: value?.metadata?.phone_number_id,
  // Media fields
  image_id: msg.image?.id || null,
  image_mime: msg.image?.mime_type || null,
  document_id: msg.document?.id || null,
  document_filename: msg.document?.filename || null,
  document_mime: msg.document?.mime_type || null,
};

return [{ json: extracted }];

// ============================================================
// RIFAH Connect - Flow 1 State Machine
// ============================================================
const msgNode = $('Extract Message').first().json;
const sessionRaw = $('Get Session').first().json;
const memberRaw = $('Get Member').first().json;

const phone = msgNode.from;
const msgType = msgNode.type || 'text';
const rawText = msgNode.text || '';
const msgText = rawText.trim().toUpperCase();
const rawTextOriginal = rawText.trim();
const hasMedia = ['image', 'document'].includes(msgType);
const mediaId = hasMedia ? (msgNode.image_id || msgNode.document_id) : null;
const mediaFilename = msgNode.document_filename || ('file_' + Date.now());
const mediaMimeType = msgNode.document_mime || 'image/jpeg';

// Parse session
const sessionDocs = sessionRaw?.data || [];
const sessionDoc = sessionDocs.length > 0 ? sessionDocs[0] : {};
let currentStep = sessionDoc.current_step || 'NEW';
let sessionData = {};
try { sessionData = JSON.parse(sessionDoc.session_data || '{}'); } catch(e) {}
const sessionName = sessionDoc.name || null;

// Parse existing member
const memberDocs = memberRaw?.data || [];
const memberExists = memberDocs.length > 0;
const member = memberExists ? memberDocs[0] : null;

let responseMsg = '';
let nextStep = currentStep;
let action = 'none';
let actionData = {};

// ---- HELPER: Main Menu ----
function mainMenu() {
  return `👋 *Welcome to RIFAH Connect!*\n_Connecting 1 Lakh+ Businesses_\n\nPlease select an option:\n\n1️⃣ Register / Update Business\n2️⃣ Find Vendors & Buyers\n3️⃣ Post a Requirement\n4️⃣ My Profile\n5️⃣ Help & Support\n\n_Reply with a number (1-5)_`;
}

// ---- HELPER: Membership Menu ----
function membershipMenu() {
  return `🏷️ *Step 5: Choose Your Membership*\n\n🆓 *FREE TIER (₹0/year)*\n• Manual support\n• 2-3 WhatsApp groups\n• Basic RifahMart listing\n• 24-48 hr response time\n\n⭐ *PREMIUM TIER (₹3,000/year)*\n• 24/7 automated bot\n• 5-10 WhatsApp groups\n• Smart vendor matching\n• Dashboard access\n• Featured RifahMart listing\n• 2-4 hr response time\n\nReply: *FREE* or *PREMIUM*`;
}

// ---- STATE MACHINE ----
switch(currentStep) {

  case 'NEW':
    sessionData = { phone };
    if (memberExists) {
      responseMsg = `👋 Welcome back, *${member.full_name}*!

🪪 Your RIFAH ID: *${member.rifah_id}*
⭐ Membership: ${member.membership_tier}

What would you like to do?

1️⃣ Update my profile
2️⃣ View current info

_Reply 1 or 2_`;
      nextStep = 'EXISTING_CHOICE';
      sessionData.existing_member_id = member.name;
    sessionData.existing_rifah_id = member.rifah_id;
    } else {
      responseMsg = mainMenu();
      nextStep = 'MENU';
    }
    break;

  case 'MENU':
    if (msgText === '1') {
      if (memberExists) {
        responseMsg = `👋 Welcome back, *${member.full_name}*!\n\n🪪 Your RIFAH ID: *${member.rifah_id}*\n⭐ Membership: ${member.membership_tier}\n\nWhat would you like to do?\n\n1️⃣ Update my profile\n2️⃣ View current info\n\n_Reply 1 or 2_`;
        nextStep = 'EXISTING_CHOICE';
        sessionData.existing_member_id = member.name;
        sessionData.existing_rifah_id = member.rifah_id;
      } else {
        responseMsg = `✅ Let's get you registered with RIFAH!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?`;
        nextStep = 'Q1';
      }
    } else if (['2','3','4','5'].includes(msgText)) {
      responseMsg = `🚧 This feature is coming soon!\n\nReply *1* to register your business.`;
    } else {
      if (memberExists) {
        responseMsg = `👋 Welcome back, *${member.full_name}*!

🪪 Your RIFAH ID: *${member.rifah_id}*
⭐ Membership: ${member.membership_tier}

What would you like to do?

1️⃣ Update my profile
2️⃣ View current info

_Reply 1 or 2_`;
        nextStep = 'EXISTING_CHOICE';
        sessionData.existing_member_id = member.name;
    sessionData.existing_rifah_id = member.rifah_id;
      } else {
        responseMsg = mainMenu();
        nextStep = 'MENU';
      }
    }
    break;

  case 'EXISTING_CHOICE':
    if (msgText === '1') {
      responseMsg = `✏️ Let's update your profile!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?\n_(Current: ${member ? member.full_name : 'N/A'})_`;
      nextStep = 'Q1';
      sessionData.is_update = true;
    } else if (msgText === '2') {
      const m = member || {};
      responseMsg = `📋 *Your Current RIFAH Profile*\n\n🪪 ID: *${m.rifah_id || 'N/A'}*\n👤 Name: ${m.full_name || 'N/A'}\n🏢 Business: ${m.business_name || 'N/A'}\n📍 Location: ${m.city_state || 'N/A'}\n🏭 Industry: ${m.industry || 'N/A'}\n⭐ Tier: ${m.membership_tier || 'N/A'}\n📊 Status: ${m.status || 'N/A'}\n🌐 RifahMart: ${m.rifahmart_url || 'Pending'}\n\nReply *1* for main menu.`;
      nextStep = 'MENU';
    } else {
      responseMsg = `Please reply *1* to update profile or *2* to view info.`;
    }
    break;

  case 'Q1':
    if (!rawTextOriginal || rawTextOriginal.length < 2) {
      responseMsg = `❌ Please enter a valid full name.\n\n👤 What is your *full name*?`;
    } else {
      sessionData.full_name = rawTextOriginal;
      responseMsg = `✅ Got it, *${rawTextOriginal}*!\n\n*Question 2 of 6*\n\n🏢 What is your *business name*?`;
      nextStep = 'Q2';
    }
    break;

  case 'Q2':
    if (!rawTextOriginal || rawTextOriginal.length < 2) {
      responseMsg = `❌ Please enter a valid business name.\n\n🏢 What is your *business name*?`;
    } else {
      sessionData.business_name = rawTextOriginal;
      responseMsg = `✅ Got it!\n\n*Question 3 of 6*\n\n📍 Which *city and state* is your business located in?\n\n_Example: Pune, Maharashtra_`;
      nextStep = 'Q3';
    }
    break;

  case 'Q3':
    if (!rawTextOriginal || rawTextOriginal.length < 3) {
      responseMsg = `❌ Please enter your city and state.\n\n📍 Which *city and state* are you in?\n_Example: Pune, Maharashtra_`;
    } else {
      sessionData.city_state = rawTextOriginal;
      responseMsg = `✅ Got it!\n\n*Question 4 of 6*\n\n🏭 What is your *industry / business type*?\n\n_Examples: Manufacturing, Trading, Services, Retail, Export-Import, IT, Healthcare, Food & Beverages_`;
      nextStep = 'Q4';
    }
    break;

  case 'Q4':
    if (!rawTextOriginal || rawTextOriginal.length < 2) {
      responseMsg = `❌ Please enter your industry type.\n\n🏭 What is your *industry / business type*?`;
    } else {
      sessionData.industry = rawTextOriginal;
      responseMsg = `✅ Got it!\n\n*Question 5 of 6*\n\n📅 How many *years* has your business been operating?\n\n_Reply with a number (e.g., 5)_`;
      nextStep = 'Q5';
    }
    break;

  case 'Q5':
    const yearsNum = parseInt(msgText.replace(/[^0-9]/g, ''));
    if (isNaN(yearsNum) || yearsNum < 0 || yearsNum > 200) {
      responseMsg = `❌ Please enter a valid number of years.\n\n📅 How many *years* has your business been operating?`;
    } else {
      sessionData.years_operating = yearsNum;
      responseMsg = `✅ Got it!\n\n*Question 6 of 6*\n\n📱 Please *confirm your WhatsApp number*:\n\n*+${phone}*\n\nReply *YES* to confirm, or type a different number.`;
      nextStep = 'Q6';
    }
    break;

  case 'Q6':
    if (msgText === 'YES' || msgText === 'Y') {
      sessionData.confirmed_phone = phone;
      responseMsg = `✅ Number confirmed: *+${phone}*\n\n📄 *Step 3: Document Verification*\n\nPlease upload your *business verification document*:\n\n• Udyam Registration Certificate\n• OR GST Registration Certificate\n\n_Accepted: PDF, JPG, PNG_`;
      nextStep = 'DOC_UPLOAD';
    } else if (/^[0-9]{10,13}$/.test(msgText.replace(/[^0-9]/g, ''))) {
      sessionData.confirmed_phone = msgText.replace(/[^0-9]/g, '');
      responseMsg = `✅ Using number: *+${sessionData.confirmed_phone}*\n\n📄 *Step 3: Document Verification*\n\nPlease upload your *business verification document*:\n\n• Udyam Registration Certificate\n• OR GST Registration Certificate\n\n_Accepted: PDF, JPG, PNG_`;
      nextStep = 'DOC_UPLOAD';
    } else {
      responseMsg = `Please reply *YES* to confirm +${phone}, or enter your correct 10-digit number.`;
    }
    break;

  case 'DOC_UPLOAD':
    if (hasMedia && mediaId) {
      sessionData.doc_media_id = mediaId;
      sessionData.doc_filename = mediaFilename;
      sessionData.doc_media_type = msgType;
      sessionData.doc_mime = mediaMimeType;
      responseMsg = `✅ Document received!\n\n📦 *Step 4: Product Materials*\n_(Optional but recommended)_\n\nUpload your product materials to attract more buyers:\n\n• Product catalogs (PDF)\n• Product images (JPG/PNG)\n• Brochures / marketing materials\n\n_You can upload multiple files._\n_Reply *SKIP* to skip, or *DONE* when finished uploading._`;
      nextStep = 'PRODUCT_UPLOAD';
      action = 'download_doc';
      actionData = { media_id: mediaId, media_type: msgType, filename: mediaFilename };
    } else {
      responseMsg = `❌ Please upload your document as a file.\n\n📄 Upload your *Udyam Registration* or *GST Certificate* (PDF, JPG, or PNG):`;
    }
    break;

  case 'PRODUCT_UPLOAD':
    const pMaterials = sessionData.product_materials || [];
    if (msgText === 'SKIP' || msgText === 'DONE') {
      sessionData.product_materials = pMaterials;
      responseMsg = membershipMenu();
      nextStep = 'TIER_SELECT';
    } else if (hasMedia && mediaId) {
      pMaterials.push({ media_id: mediaId, type: msgType, filename: mediaFilename });
      sessionData.product_materials = pMaterials;
      const count = pMaterials.length;
      responseMsg = `✅ File ${count} received!\n\nUpload another file, or reply *DONE* when finished.`;
      nextStep = 'PRODUCT_UPLOAD';
      action = 'download_doc';
      actionData = { media_id: mediaId, media_type: msgType, filename: mediaFilename };
    } else {
      responseMsg = `Please upload a product file (PDF/JPG/PNG), or reply *SKIP* to skip / *DONE* if finished.`;
    }
    break;

  case 'TIER_SELECT':
    if (msgText === 'FREE') {
      sessionData.tier = 'FREE';
      responseMsg = '⏳ Processing your registration...';
      nextStep = 'PROCESSING';
      action = 'create_free_member';
      actionData = { ...sessionData };
    } else if (msgText === 'PREMIUM') {
      sessionData.tier = 'PREMIUM';
      responseMsg = `💳 *Premium Membership: ₹3,000/year*\n\nPlease make payment to:\n\n🔸 *UPI ID:* rifah@upi\n🔸 *Bank Transfer:*\n   Account: RIFAH Chamber of Commerce\n   A/C No: 1234567890\n   IFSC: HDFC0001234\n   Bank: HDFC Bank\n\nAfter payment, please:\n📸 Upload *payment screenshot*\nOR\n💬 Send *transaction ID / UTR number*\n\n_We verify within 2 hours._`;
      nextStep = 'PAYMENT_WAIT';
    } else {
      responseMsg = membershipMenu();
    }
    break;

  case 'PAYMENT_WAIT':
    if (hasMedia && mediaId) {
      sessionData.payment_proof_id = mediaId;
      sessionData.payment_type = 'screenshot';
      responseMsg = `✅ Payment screenshot received!\n\n⏳ *Verifying your payment...*\n\nOur team will confirm within *2 hours*.\nYou'll receive a WhatsApp confirmation once verified.\n\nThank you for choosing RIFAH Premium! 🙏`;
      nextStep = 'PAYMENT_PENDING';
      action = 'create_premium_pending';
      actionData = { ...sessionData };
    } else if (rawTextOriginal.length >= 8) {
      sessionData.payment_transaction_id = rawTextOriginal;
      sessionData.payment_type = 'transaction_id';
      responseMsg = `✅ Transaction ID received: *${rawTextOriginal}*\n\n⏳ *Verifying your payment...*\n\nOur team will confirm within *2 hours*.\nYou'll receive a WhatsApp confirmation once verified.\n\nThank you for choosing RIFAH Premium! 🙏`;
      nextStep = 'PAYMENT_PENDING';
      action = 'create_premium_pending';
      actionData = { ...sessionData };
    } else {
      responseMsg = `Please upload your *payment screenshot* or send your *transaction ID / UTR number*.\n\n💳 UPI: rifah@upi`;
    }
    break;

  case 'PAYMENT_PENDING':
    responseMsg = `⏳ Your payment is being verified. You'll receive confirmation shortly.\n\nIf you have questions, contact us directly.`;
    break;

  case 'PROCESSING':
    responseMsg = `⏳ Processing your registration...`;
    break;


  case 'COMPLETED':
    sessionData = { phone };
    if (memberExists) {
      responseMsg = `👋 Welcome back, *${member.full_name}*!

🪪 Your RIFAH ID: *${member.rifah_id}*
⭐ Membership: ${member.membership_tier}

What would you like to do?

1️⃣ Update my profile
2️⃣ View current info

_Reply 1 or 2_`;
      nextStep = 'EXISTING_CHOICE';
      sessionData.existing_member_id = member.name;
      sessionData.existing_rifah_id = member.rifah_id;
    } else {
      responseMsg = mainMenu();
      nextStep = 'MENU';
    }
    break;

  default:
    sessionData = { phone };
    responseMsg = mainMenu();
    nextStep = 'MENU';
}

return [{
  json: {
    phone,
    responseMsg,
    nextStep,
    action,
    actionData: JSON.stringify(actionData),
    sessionData: JSON.stringify(sessionData),
    sessionName,
    currentStep,
    msgType,
    hasMedia,
    mediaId,
    shouldSendMsg: responseMsg.length > 0
  }
}];

// Determine if we should POST (new) or PUT (update) session
const smData = $('State Machine').first().json;
const sessionName = smData.sessionName;

return [{
  json: {
    isNew: !sessionName,
    sessionName,
    phone: smData.phone,
    nextStep: smData.nextStep,
    sessionData: smData.sessionData,
    now: new Date().toISOString().replace('T', ' ').substring(0, 19)
  }
}];

// Generate RIFAH ID and build member payload for FREE tier
const stateMachineData = $('State Machine').first().json;
const countResult = $input.first().json;

const actionData = JSON.parse(stateMachineData.actionData || '{}');
const existingCount = countResult?.data?.length || 0;
const newIndex = String(existingCount + 1).padStart(4, '0');
const year = new Date().getFullYear();
const rifah_id = `RIF-FREE-${year}-${newIndex}`;

// Build business name slug for RifahMart URL
const slug = (actionData.business_name || 'business')
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 50);

const rifahmart_url = `https://rifahmart.com/${rifah_id}/${slug}`;

const payload = {
  doctype: 'RIFAH Member',
  rifah_id,
  full_name: actionData.full_name || '',
  whatsapp_number: actionData.phone || stateMachineData.phone,
  business_name: actionData.business_name || '',
  city_state: actionData.city_state || '',
  industry: actionData.industry || '',
  years_operating: actionData.years_operating || 0,
  membership_tier: 'FREE',
  status: 'Pending Admin Review',
  rifahmart_url,
  rifahmart_status: 'Published',
  registration_date: new Date().toISOString().replace('T', ' ').substring(0, 19)
};

return [{
  json: {
    payload,
    rifah_id,
    rifahmart_url,
    phone: stateMachineData.phone,
    business_name: actionData.business_name || '',
    city_state: actionData.city_state || '',
    industry: actionData.industry || '',
    full_name: actionData.full_name || ''
  }
}];

